#include <bits/stdc++.h>
using namespace std;

const int N=5010,INF=0x3f3f3f3f;

struct Edge{
    int to,val;
};

bool operator<(Edge x,Edge y){
    return x.val>y.val;
}

int n,m,dis[N<<1];
vector<Edge> g[N];
bool b[N<<1];

void Dijkstra(){
    memset(dis,0x3f,sizeof(dis));
    priority_queue<Edge> q;
    dis[1]=0;
    q.push({1,0});
    while(q.size()){
        while(q.size() && b[q.top().to])
            q.pop();
        if(q.empty())
            break;
        int x=q.top().to,d=q.top().val;
        b[x]=1,q.pop();
        if(x>n)
            x-=n;
        for(Edge y:g[x]){
            if(dis[y.to]>d+y.val){
                dis[y.to+n]=dis[y.to];
                dis[y.to]=d+y.val;
                q.push({y.to,d+y.val});
                q.push({y.to+n,dis[y.to+n]});
            }else if(dis[y.to]<d+y.val && dis[y.to+n]>d+y.val){
                dis[y.to+n]=d+y.val;
                q.push({y.to+n,d+y.val});
            }
        }
    }
}

int main(){
    scanf("%d%d",&n,&m);
    for(int i=1,u,v,w;i<=m;i++){
        scanf("%d%d%d",&u,&v,&w);
        g[u].push_back({v,w});
        g[v].push_back({u,w});
    }
    Dijkstra();
    printf("%d",dis[n+n]);
    return 0;
}
